const p = $json.body || $json;
const errors = [];
if (p.schema_version !== '1.0') errors.push('schema_version must be "1.0"');
if (!p.event || !['recording_completed', 'recording_abandoned'].includes(p.event)) errors.push('event must be recording_completed or recording_abandoned');
if (!p.candidate || !p.candidate.workable_id) errors.push('candidate.workable_id required');
if (!p.candidate || !p.candidate.role_type) errors.push('candidate.role_type required');
if (!p.candidate || ![1, 2, 3].includes(p.candidate.tier)) errors.push('candidate.tier must be 1|2|3');
if (!p.recording || !p.recording.session_id) errors.push('recording.session_id required');
if (p.event === 'recording_completed' && (!Array.isArray(p.recording?.audio_files) || p.recording.audio_files.length === 0)) {
  errors.push('recording.audio_files[] required for recording_completed');
}
if (errors.length) {
  throw new Error('Contract 1 validation failed: ' + errors.join('; '));
}
return [{ json: { ...p, _validated: true } }];

const upstream = $input.first().json;
const incoming = $('Validate Contract 1 Payload').item.json;
let existing = null;
if (Array.isArray(upstream)) existing = upstream[0] || null;
else if (Array.isArray(upstream.data)) existing = upstream.data[0] || null;
const TERMINAL = ['scored', 'disqualified', 'abandoned'];
if (existing && existing.status && TERMINAL.includes(existing.status)) {
  return [];
}
return [{ json: incoming }];

