const items = $input.all();
const round1 = (n) => typeof n === 'number' ? Math.round(n * 10) / 10 : 0;
const toFive = (s100) => Math.max(0, Math.min(5, (s100 || 0) / 20));
const toCefr = (s) => s >= 90 ? 'C1' : s >= 80 ? 'B2+' : s >= 70 ? 'B2' : s >= 60 ? 'B1+' : s >= 50 ? 'B1' : 'A2+';
const pron = [], flu = [], gra = [], voc = [], coh = [];
const transcripts = [];
const flags = [];
let failures = 0;
for (const item of items) {
  const sp = item.json?.speech_score || item.json || {};
  if (!sp || sp.status === 'error') { failures++; continue; }
  const ss = sp.speechace_score || {};
  if (typeof ss.pronunciation === 'number') pron.push(ss.pronunciation);
  if (typeof ss.fluency === 'number') flu.push(ss.fluency);
  if (typeof ss.grammar === 'number') gra.push(ss.grammar);
  if (typeof ss.vocab === 'number') voc.push(ss.vocab);
  if (typeof ss.coherence === 'number') coh.push(ss.coherence);
  if (sp.text || sp.transcript) transcripts.push(sp.text || sp.transcript);
}
if (failures >= 3) flags.push('audio_quality_poor');
const avg = (a) => a.length ? a.reduce((x,y)=>x+y, 0) / a.length : 0;
const dim = (a) => ({ score: round1(toFive(avg(a))), cefr: toCefr(avg(a)) });
const speechace_5dim = {
  pronunciation: dim(pron),
  fluency: dim(flu),
  grammar: dim(gra),
  vocabulary: dim(voc),
  coherence: dim(coh),
};
const ctx = $('Validate Contract 1 Payload').item.json;
const audio_files = ctx.recording?.audio_files || [];
const transcript_map = {};
for (let i = 0; i < items.length; i++) {
  const af = audio_files[i] || {};
  const qid = (af.question_id || ('q' + (i+1))).toLowerCase();
  transcript_map[qid] = transcripts[i] || '';
}
return [{ json: {
  ...ctx,
  speechace_5dim,
  speechace_transcripts: transcript_map,
  speechace_flags: flags,
  speechace_failure_count: failures,
} }];

const resp = $json;
const txt = (resp.content && resp.content[0] && resp.content[0].text) ? resp.content[0].text : '{}';

let comp;
try {
  const cleaned = txt.replace(/^\s*\u0060\u0060\u0060json\s*/i, '').replace(/\s*\u0060\u0060\u0060\s*$/i, '').trim();
  comp = JSON.parse(cleaned);
} catch (e) {
  comp = {
    schema_version: '1.1',
    model: 'claude-sonnet-4-6',
    call_timestamp: new Date().toISOString(),
    candidate_ref: { workable_id: '', session_id: '' },
    comprehension: { cefr: 'B1', numeric_score: 3.0, paraphrase_accuracy: 'partial', instruction_following: 'adequate', relevance: 'partial' },
    qualitative: { claude_note: 'Comprehension parse failed; B1/3.0 fallback.' },
    interview_observations: [],
    risk_indicators: null,
    flags: ['comprehension_parse_fallback'],
    cost_usd: 0,
  };
}

comp.model = 'claude-sonnet-4-6';
comp.call_timestamp = new Date().toISOString();
comp.schema_version = '1.1';

const ctx = $('Aggregate SpeechSuper 5-dim').item.json;
const sp = ctx.speechace_5dim;
const tier = ctx.candidate.tier;

const weights = { pronunciation: 0.25, comprehension: 0.20, fluency: 0.20, grammar: 0.15, coherence: 0.10, vocabulary: 0.10 };
const round1 = (n) => Math.round(n * 10) / 10;

const dimEntry = (raw_0_5, cefr, weight) => ({
  score: round1(raw_0_5 * weight * 6),
  cefr,
  weight,
  max: round1(weight * 30),
});

const normalizeCompTo5 = (raw) => {
  const n = Number(raw) || 0;
  if (n <= 5) return Math.max(0, n);
  if (n <= 100) return n / 20;
  return 5;
};
const compRaw5 = normalizeCompTo5(comp.comprehension?.numeric_score);

const dims = {
  pronunciation: dimEntry(sp.pronunciation.score, sp.pronunciation.cefr, weights.pronunciation),
  comprehension: dimEntry(compRaw5, comp.comprehension?.cefr || 'B1', weights.comprehension),
  fluency: dimEntry(sp.fluency.score, sp.fluency.cefr, weights.fluency),
  grammar: dimEntry(sp.grammar.score, sp.grammar.cefr, weights.grammar),
  coherence: dimEntry(sp.coherence.score, sp.coherence.cefr, weights.coherence),
  vocabulary: dimEntry(sp.vocabulary.score, sp.vocabulary.cefr, weights.vocabulary),
};

let overall = 0;
for (const k of Object.keys(dims)) overall += dims[k].score;
overall = round1(overall);

const thresholds = { 1: { pass: 22, borderline: 16 }, 2: { pass: 25, borderline: 19 }, 3: { pass: 27, borderline: 21 } };
const t = thresholds[tier] || thresholds[1];
const verdict = overall >= t.pass ? 'PASS' : overall >= t.borderline ? 'BORDERLINE' : 'FAIL';

const dimEntries = Object.entries(dims);
dimEntries.sort((a, b) => (b[1].score / b[1].max) - (a[1].score / a[1].max));
const strongest = dimEntries[0][0];
const weakest = dimEntries[dimEntries.length - 1][0];

const recommendation = verdict === 'PASS'
  ? { action: 'AUTO_ADVANCE', next_stage: 'Preliminary Assessments', rationale_short: 'Advance after 24h recruiter review window.' }
  : verdict === 'BORDERLINE'
  ? { action: 'RECRUITER_REVIEW', next_stage: null, rationale_short: 'Held for recruiter review — BORDERLINE does not auto-advance.' }
  : { action: 'AUTO_REJECT', next_stage: null, rationale_short: 'Reject after 48h recruiter review window.' };

const grade = verdict === 'PASS' ? 2 : verdict === 'BORDERLINE' ? 1 : 0;
const allFlags = [...(ctx.speechace_flags || []), ...(comp.flags || [])];

const _rec = ctx.recording || {};
const _recSession = _rec.session_id || '';
const recording_url = _recSession
  ? ('https://sv-ats.vercel.app/review/' + encodeURIComponent(_recSession))
  : null;

const scorecard = {
  schema_version: '1.0',
  generated_at: new Date().toISOString(),
  workflow_run_id: 'wfc_' + Date.now(),
  recording_url,
  candidate: { workable_id: ctx.candidate.workable_id },
  role: { role_code: ctx.candidate.role_type, tier, tier_label: 'Tier ' + tier },
  scores: {
    overall,
    overall_max: 30,
    cefr_overall: comp.comprehension.cefr || 'B1',
    verdict,
    dimensions: dims,
  },
  qualitative: {
    claude_note: comp.qualitative?.claude_note || '',
    strongest_dimension: strongest,
    weakest_dimension: weakest,
    flags: [...new Set(allFlags)],
    interview_observations: Array.isArray(comp.interview_observations) ? comp.interview_observations : [],
    risk_indicators: comp.risk_indicators || null,
  },
  recommendation,
};

const first_name = ctx.candidate.firstname || ctx.candidate.first_name || '';
const role_label = ctx.candidate.role_label || ctx.candidate.role_type || '';

return [{ json: { ...ctx, scorecard, verdict, grade, comprehension: comp, first_name, role_label, candidate_id: ctx.candidate.workable_id } }];

const sc = $json.scorecard;
const LINE_WIDTH = 60;
const DIVIDER = '━'.repeat(56);
const VERDICT_ICON = { PASS: '✅', BORDERLINE: '⚠', FAIL: '✗' };
const DIMENSION_ORDER = [['pronunciation','Pronunciation'],['comprehension','Comprehension'],['fluency','Fluency'],['grammar','Grammar'],['coherence','Coherence'],['vocabulary','Vocabulary']];
const CEFR_BAND = {'C2':'strong','C1':'strong','B2+':'on_target','B2':'on_target','B1+':'below','B1':'below','A2+':'floor','A2':'floor','A1+':'floor','A1':'floor'};
const BAND_LABEL = {strong:'✓ strong',on_target:'✓ on target',below:'⚠ below',floor:'✗ floor'};
function dimensionDelta(dimKey, dim, strongestKey, weakestKey, verdict) {
  const band = CEFR_BAND[dim.cefr] || 'floor';
  const base = BAND_LABEL[band];
  if (dimKey === strongestKey && verdict !== 'FAIL') return base + ' (top)';
  if (dimKey === weakestKey) return base + ' (low)';
  return base;
}
function wrap(text, width) {
  const words = (text || '').split(/\s+/);
  const lines = []; let cur = '';
  for (const w of words) {
    if (!cur) { cur = w; continue; }
    if ((cur + ' ' + w).length <= width) cur += ' ' + w;
    else { lines.push(cur); cur = w; }
  }
  if (cur) lines.push(cur);
  return lines;
}
function wrapWithPrefix(prefix, text, totalWidth) {
  const firstLineWidth = totalWidth - prefix.length;
  const words = (text || '').split(/\s+/);
  const lines = []; let cur = ''; let first = true;
  for (const w of words) {
    const limit = first ? firstLineWidth : totalWidth;
    if (!cur) cur = w;
    else if ((cur + ' ' + w).length <= limit) cur += ' ' + w;
    else { lines.push(first ? prefix + cur : cur); cur = w; first = false; }
  }
  if (cur) lines.push(first ? prefix + cur : cur);
  return lines;
}
function formatTimestamp(iso) {
  const d = new Date(iso);
  const pad = (n) => String(n).padStart(2, '0');
  return d.getUTCFullYear() + '-' + pad(d.getUTCMonth()+1) + '-' + pad(d.getUTCDate()) + ' ' + pad(d.getUTCHours()) + ':' + pad(d.getUTCMinutes()) + ' UTC';
}
const lines = [];
lines.push('🤖 AI SCREENING COMPLETE  •  ' + formatTimestamp(sc.generated_at));
lines.push('');
const icon = VERDICT_ICON[sc.scores.verdict] || '';
lines.push(icon + ' ' + sc.scores.verdict + ' — Overall ' + sc.scores.overall.toFixed(1) + ' / ' + sc.scores.overall_max + ' · CEFR ' + sc.scores.cefr_overall);
lines.push('');
wrapWithPrefix('Recommendation: ', sc.recommendation.rationale_short || '', LINE_WIDTH).forEach(l => lines.push(l));
lines.push('');
lines.push(DIVIDER);
lines.push('');
lines.push('DIMENSION BREAKDOWN');
lines.push('');
const strongest = sc.qualitative.strongest_dimension;
const weakest = sc.qualitative.weakest_dimension;
for (const [key, label] of DIMENSION_ORDER) {
  const d = sc.scores.dimensions[key];
  if (!d) continue;
  lines.push(label + ': ' + d.score.toFixed(1) + ' / ' + d.max.toFixed(1) + ' · ' + d.cefr + ' · ' + dimensionDelta(key, d, strongest, weakest, sc.scores.verdict));
}
lines.push('');
lines.push('NARRATIVE');
lines.push('');
wrap(sc.qualitative.claude_note || '', LINE_WIDTH).forEach(l => lines.push(l));
lines.push('');
const observations = sc.qualitative.interview_observations;
if (Array.isArray(observations) && observations.length > 0) {
  lines.push('INTERVIEW OBSERVATIONS');
  lines.push('');
  observations.forEach(o => {
    const qid = (o.question_id || '').toUpperCase();
    const head = qid ? (qid + ' — ' + o.label + ': ') : (o.label + ': ');
    wrapWithPrefix(head, o.observation || '', LINE_WIDTH).forEach(l => lines.push(l));
  });
  lines.push('');
}
const risk = sc.qualitative.risk_indicators;
if (risk && typeof risk === 'object') {
  const RISK_ORDER = [['communication','Communication Risk'],['reliability','Reliability Risk'],['customer_facing','Customer-Facing Risk'],['decision_making','Decision-Making Risk'],['executive_support','Executive Support Risk']];
  lines.push('RISK INDICATORS');
  lines.push('');
  for (const [key, label] of RISK_ORDER) {
    if (risk[key]) lines.push(label + ': ' + risk[key]);
  }
  lines.push('');
}
if (sc.qualitative.flags && sc.qualitative.flags.length > 0) {
  lines.push('NOTES');
  lines.push('');
  sc.qualitative.flags.forEach(f => lines.push('⚠ ' + f));
  lines.push('');
}
if (sc.recording_url) {
  lines.push('RECORDING');
  lines.push('');
  lines.push(sc.recording_url);
  lines.push('');
}
lines.push('SYSTEM ACTION');
lines.push('');
if (sc.recommendation.action === 'AUTO_ADVANCE') {
  lines.push('Held 24h for recruiter review, then auto-advances to: ' + sc.recommendation.next_stage);
} else if (sc.recommendation.action === 'AUTO_REJECT') {
  lines.push('Held 48h for recruiter review, then auto-rejected.');
} else {
  lines.push('Held in Interview stage for recruiter review.');
  lines.push('No auto-advance or auto-reject.');
}
lines.push('');
lines.push(DIVIDER);
lines.push('Generated by SV AI Screening v2.0');
lines.push('Run ID: ' + sc.workflow_run_id);
const rendered = lines.join('\n');
return [{ json: { ...$json, rendered_scorecard_string: rendered } }];

const sc = $json.scorecard;
const dims = sc.scores.dimensions;
const trunc = (s, n) => !s ? '' : (s.length <= n ? s : s.slice(0, n-1).trimEnd() + '…');
const fmt = (n) => typeof n === 'number' ? n.toFixed(1) : '';
const recUrl = 'https://sv-ats.vercel.app/review/' + encodeURIComponent($json.recording?.session_id || '');
const row = {
  'Candidate ID': sc.candidate.workable_id || '',
  'Job ID': $json.candidate?.job_id || '',
  'Role Type': sc.role.role_code || '',
  'Tier': String(sc.role.tier || ''),
  'Interview Date': sc.generated_at || '',
  'Overall Score (/30)': fmt(sc.scores.overall),
  'Verdict': sc.scores.verdict || '',
  'CEFR': sc.scores.cefr_overall || '',
  'Pronunciation': fmt(dims.pronunciation?.score),
  'Fluency': fmt(dims.fluency?.score),
  'Grammar': fmt(dims.grammar?.score),
  'Vocabulary': fmt(dims.vocabulary?.score),
  'Coherence': fmt(dims.coherence?.score),
  'Comprehension': fmt(dims.comprehension?.score),
  'Strongest Q': sc.qualitative?.strongest_dimension || '',
  'Weakest Q': sc.qualitative?.weakest_dimension || '',
  'Flags': Array.isArray(sc.qualitative?.flags) ? sc.qualitative.flags.join(', ') : '',
  'Claude Note (truncated)': trunc(sc.qualitative?.claude_note || '', 300),
  'Scorecard URL': recUrl,
};
return [{ json: { ...$json, ...row } }];

const sc = $json.scorecard;
const completenessOk = !($json.speechace_flags || []).includes('audio_quality_poor');
const answeredCount = Object.values($json.speechace_transcripts || {}).filter(t => t && t.trim().length > 5).length;
const totalQuestions = ($json.recording?.audio_files || []).length || 7;
const missingCount = totalQuestions - answeredCount;
const incomplete = missingCount >= 2;
return [{ json: { ...$json, incomplete, missingCount, answeredCount, completenessOk } }];

const ctx = $('Build Sheet Row (19 cols)').item.json;
const dqRationale = '\n\n— DQ rationale: AI screening determined English proficiency and job fit below the threshold for this role tier. This decision was based on the AI-scored recording alone and does not reflect overall potential. Candidate may re-apply for future roles.';
const body = (ctx.rendered_scorecard_string || '') + dqRationale;
return [{ json: { ...ctx, fail_comment_body: body, fail_comment_body_json_str: JSON.stringify(body) } }];

